VALUES
  ('judicial-57112235-moex-00247', 'judicial-57112235', 'judicial-57112235-moex-113-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '受刑人甲因搶奪罪入監服刑，於民國113年8月10日刑期執行屆滿釋放，依監獄行刑法規定，應於 何時釋放之？', '["113年8月10日中午12時前", "113年8月10日中午12時後", "113年8月11日中午12時前", "113年8月11日中午12時後"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "985208735e01", "answer_pdf_sha1": "06835924ef33", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00248', 'judicial-57112235', 'judicial-57112235-moex-113-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依監獄行刑法第3條規定，監獄行刑之對象，下列何者錯誤？', '["判處徒刑者", "罰金易服勞役者", "判處拘役者", "受裁定羈押者"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "985208735e01", "answer_pdf_sha1": "06835924ef33", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00249', 'judicial-57112235', 'judicial-57112235-moex-113-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依據監獄行刑法以及相關法規之規定，下列敘述何者錯誤？', '["監獄行刑法之主管機關與監督機關及監獄，就執行本法事項，僅應對於受刑人不利之情形，加以注意", "監獄，指法務部矯正署所屬監獄，及監獄設置之分監、女監", "監獄行刑法所稱嚴為分界，指以監內建築物、同一建築物之不同樓層或圍牆隔離監禁之", "監獄行刑法所稱分別監禁，指於監獄內之不同舍房、工場或指定之區域分別監禁之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "985208735e01", "answer_pdf_sha1": "06835924ef33", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00250', 'judicial-57112235', 'judicial-57112235-moex-113-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依據監獄行刑法以及相關法規之規定，下列敘述何者正確？', '["受刑人之接見或通信對象，監獄絕對不得予限制或禁止", "監獄應於國定例假日或其他休息日辦理接見", "監獄對於請求接見者認為有妨害監獄秩序、安全或受刑人利益時，得拒絕之", "受刑人之接見，除法規另有規定外，每星期二次，接見時間以一小時為限"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "985208735e01", "answer_pdf_sha1": "06835924ef33", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00251', 'judicial-57112235', 'judicial-57112235-moex-113-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '受刑人入監時，應行健康檢查，受刑人不得拒絕，監獄行刑法定有明文，當受刑人於入監時，經行健 康檢查後，發現受刑人有下列那一種情形，應予拒絕收監？', '["有客觀事實足認受刑人甲身心狀況欠缺辨識能力，但仍能處理自己事務", "受刑人乙現罹患疾病", "受刑人丙患有重度身心障礙，不能於監獄自理生活", "受刑人丁懷胎四月"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "985208735e01", "answer_pdf_sha1": "06835924ef33", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00252', 'judicial-57112235', 'judicial-57112235-moex-113-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '監獄行刑之處所，原則上係在監獄內，但依監獄行刑法規定，刑罰雖非於監獄內執行，亦可視同在監 獄內執行並予以計算刑期。關於視同在監獄內執行並予以計算刑期之敘述，下列何者錯誤？', '["受刑人在監外作業，若於指定時間內回監，在外期間算入執行刑期", "受刑人外出參加公益或教化活動並依時回監，在外期間予以計算刑期", "受刑人奉准返家奔喪並依限返監，在外期間予以計算刑期", "因天災、事變而暫行釋放之受刑人，釋放後六十小時內，未到指定地點報到，在外期間予以計算刑期"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "985208735e01", "answer_pdf_sha1": "06835924ef33", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00253', 'judicial-57112235', 'judicial-57112235-moex-113-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '為紓解監獄嚴重超額狀態，依監獄行刑法及監獄受刑人移監作業辦法，當監獄受刑人人數嚴重超額時， 法務部矯正署視各監獄收容之實際狀況，必要時得機動調整移監，將嚴重超額監獄收容之受刑人移送 至其他監獄收容。所謂嚴重超額，下列敘述何者正確？', '["監獄實際收容人數逾核定容額百分之五", "監獄實際收容人數逾核定容額百分之十", "監獄實際收容人數逾核定容額百分之十五", "監獄實際收容人數逾核定容額百分之二十"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "985208735e01", "answer_pdf_sha1": "06835924ef33", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00254', 'judicial-57112235', 'judicial-57112235-moex-113-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '行刑累進處遇之設計是由嚴而寬的階段性處遇，有關於該制度之設計目的，下列何者沒有直接關聯？', '["促進受刑人衛生保健習慣，提升監獄環境整潔", "促使受刑人保持善行，遵守紀律", "促進更生，培養作業技能", "實現個別化處遇原則，提升社會適應能力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "985208735e01", "answer_pdf_sha1": "06835924ef33", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00255', 'judicial-57112235', 'judicial-57112235-moex-113-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '當受刑人在監有危害監獄安全或其安全有受到危害之虞時，依法得施以隔離保護，有關隔離保護之敘 述，下列何者正確？', '["受刑人被施以隔離保護期間得限制或禁止持有或使用衣被、盥洗用具及電器物品，並得禁止吸菸及 暫停作業", "施以隔離保護應由機關人員填寫報告表並經核准後，始得為之。但緊急時，得先行實施，並立即報 告機關長官", "施以隔離保護後，每滿7日機關應安排醫事人員進行訪視。必要時，亦得隨時訪視並進行評估", "施以隔離保護後，其輔導、給養、衛生醫療、運動、接見通信及其他必要之處遇，仍應與一般受刑 人有所區別"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "985208735e01", "answer_pdf_sha1": "06835924ef33", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00256', 'judicial-57112235', 'judicial-57112235-moex-113-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '甲因無期徒刑，在監執行許久，在知悉所報請之假釋案經不予許可後，在舍房內情緒失控、瘋狂怒吼 而有自殘可能，已影響囚情甚鉅，監所管理員乙經請示監獄長官後，准予施以固定保護，下列敘述何 者錯誤？', '["固定保護是一種暫時性處置措施，每次最長不得逾4小時", "原則上應將甲固定保護於病（推）床，但病床已滿，亦得固定於擔架", "施以固定保護，應由監獄人員為之", "甲被施以固定保護，得以保護性約束工具，拘束受刑人身體或四肢"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "985208735e01", "answer_pdf_sha1": "06835924ef33", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL)
